<?php
 namespace WPAICG\Utils; if (!defined('ABSPATH')) { exit; } class AIPKit_Prompt_Sanitizer { public static function sanitize(mixed $prompt, bool $trim = true): string { if (is_array($prompt) || is_object($prompt)) { return ''; } $prompt = wp_check_invalid_utf8((string) $prompt); $prompt = str_replace(["\r\n", "\r"], "\n", $prompt); $prompt = preg_replace('/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/', '', $prompt); $prompt = is_string($prompt) ? $prompt : ''; return $trim ? trim($prompt) : $prompt; } } 